import Navbar from "../navbar";
import aboutImage from "../../assets/images/about.svg";

export default function AboutMain() {
    return (
        <>
            <Navbar about="active" />
            <div className="container p-5">
                <div className="row">
                    <div className="col-12 col-md-6">
                        <h1 className="display-1" style={{ fontWeight : "550", fontFamily : "Edu+VIC+WA+NT+Beginner"}}>About</h1>
                    </div>
                    <div className="col-12 col-md-6">
                        <img src={aboutImage} alt="image profile" />
                    </div>
                </div>
            </div>
        </>
    )
}
